// ProjectCard.js
import React from 'react';
import {
  Card,
  CardContent,
  CardMedia,
  Typography,
  Box,
  Chip,
  Stack,
  CardActionArea
} from '@mui/material';
import { GitHub, Launch } from '@mui/icons-material';

const ProjectCard = ({ project }) => {
  const { title, description, image, techStack, demoLink, githubLink, emoji } = project;
  
  return (
    <Card
      sx={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        backgroundColor: 'background.paper',
        border: '1px solid',
        borderColor: 'divider',
        borderRadius: 2,
        transition: 'transform 0.3s ease-in-out, box-shadow 0.3s ease-in-out',
        '&:hover': {
          transform: 'translateY(-8px)',
          boxShadow: '0 10px 20px rgba(0,0,0,0.2)'
        }
      }}
    >
      <CardActionArea
        component="div"
        sx={{
          flexGrow: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'stretch',
          height: '100%'
        }}
      >
        <CardMedia
          component="img"
          height="200"
          image={image || `/assets/projects/placeholder.png`}
          alt={title}
          sx={{ 
            objectFit: 'cover',
            backgroundSize: 'cover',
            backgroundPosition: 'center'
          }}
        />
        <CardContent sx={{ 
          flexGrow: 1, 
          display: 'flex', 
          flexDirection: 'column',
          p: 3,
          height: '300px' // Fixed height for card content
        }}>
          <Typography variant="h5" component="div" gutterBottom sx={{ display: 'flex', alignItems: 'center' }}>
            {emoji && <Box component="span" mr={1} fontSize="1.5rem">{emoji}</Box>}
            {title}
          </Typography>
          <Typography 
            variant="body2" 
            color="text.secondary" 
            sx={{ 
              mb: 2, 
              height: '80px', // Fixed height for description
              overflow: 'hidden',
              display: '-webkit-box',
              WebkitLineClamp: 4,
              WebkitBoxOrient: 'vertical',
              textOverflow: 'ellipsis'
            }}
          >
            {description}
          </Typography>
          <Typography variant="subtitle2" color="primary" gutterBottom>
            Tech Stack:
          </Typography>
          <Stack 
            direction="row" 
            spacing={1} 
            flexWrap="wrap" 
            sx={{ 
              mb: 2,
              height: '60px', // Fixed height for tech stack
              overflow: 'hidden'
            }}
          >
            {techStack.map((tech, index) => (
              <Chip
                key={index}
                label={tech}
                size="small"
                sx={{
                  mr: 0.5,
                  mb: 0.5,
                  backgroundColor: 'primary.dark',
                  color: 'primary.contrastText'
                }}
              />
            ))}
          </Stack>
          <Box sx={{ mt: 'auto', display: 'flex', gap: 2 }}>
            {githubLink && (
              <Box
                component="a"
                href={githubLink}
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  color: 'text.secondary',
                  textDecoration: 'none',
                  '&:hover': { color: 'primary.main' }
                }}
              >
                <GitHub sx={{ mr: 0.5 }} fontSize="small" />
                <Typography variant="button">Code</Typography>
              </Box>
            )}
            {demoLink && (
              <Box
                component="a"
                href={demoLink}
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  color: 'text.secondary',
                  textDecoration: 'none',
                  '&:hover': { color: 'primary.main' }
                }}
              >
                <Launch sx={{ mr: 0.5 }} fontSize="small" />
                <Typography variant="button">Live Demo</Typography>
              </Box>
            )}
          </Box>
        </CardContent>
      </CardActionArea>
    </Card>
  );
};

export default ProjectCard;
